#include <bits/stdc++.h>
using namespace std;


int main(){
	int n;
	cin>>n;
	int a[n];
	for(int i=0;i<n;i++){
		cin>>a[i];
	}
	long q;
	cin>>q;
	for(int i=0;i<q;i++){
		long long m;
		cin>>m;
		int has = 0;
		for(int j=0;j<n;j++){
			if(a[j]==m){
				cout<<j+1<<endl;
				has = 1;
				break;
			}
		}
		if(!has){
			cout<<0<<endl;
		}
	}
	return 0;
}
